-- DevEstudos — Script completo de criação do banco

CREATE TABLE usuarios (
  id SERIAL PRIMARY KEY,
  nome VARCHAR(100) NOT NULL,
  email VARCHAR(255) UNIQUE NOT NULL,
  senha_hash VARCHAR(255) NOT NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE cursos (
  id SERIAL PRIMARY KEY,
  nome VARCHAR(150) NOT NULL,
  descricao TEXT,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE modulos (
  id SERIAL PRIMARY KEY,
  curso_id INT NOT NULL REFERENCES cursos(id),
  nome VARCHAR(150) NOT NULL,
  descricao TEXT,
  ordem INT NOT NULL
);

CREATE TABLE questoes (
  id SERIAL PRIMARY KEY,
  modulo_id INT NOT NULL REFERENCES modulos(id),
  titulo VARCHAR(200),
  pergunta TEXT NOT NULL,
  tipo VARCHAR(20) NOT NULL,
  xp INT DEFAULT 10,
  nivel VARCHAR(20) DEFAULT 'iniciante'
);

CREATE TABLE alternativas (
  id SERIAL PRIMARY KEY,
  questao_id INT NOT NULL REFERENCES questoes(id),
  texto TEXT NOT NULL,
  correta BOOLEAN DEFAULT false
);

CREATE TABLE progresso (
  id SERIAL PRIMARY KEY,
  usuario_id INT NOT NULL REFERENCES usuarios(id),
  modulo_id INT NOT NULL REFERENCES modulos(id),
  percentual DECIMAL(5,2) DEFAULT 0,
  concluido BOOLEAN DEFAULT false,
  ultimo_acesso TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE flashcards (
  id SERIAL PRIMARY KEY,
  usuario_id INT NOT NULL REFERENCES usuarios(id),
  pergunta TEXT NOT NULL,
  resposta TEXT NOT NULL,
  proxima_revisao TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX idx_questoes_modulo ON questoes(modulo_id);
CREATE INDEX idx_flashcards_revisao ON flashcards(proxima_revisao);
CREATE INDEX idx_progresso_usuario ON progresso(usuario_id);
